const express = require('express');
const http = require('http');
const socketIO = require('socket.io');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const bcrypt = require('bcryptjs');
const Database = require('better-sqlite3');
const multer = require('multer');
const path = require('path');
const fs = require('fs');

const app = express();
const server = http.createServer(app);
const io = socketIO(server, { 
  cors: { 
    origin: "http://localhost:3000",
    methods: ["GET", "POST"],
    credentials: true 
  } 
});

app.use(cors({
  origin: "http://localhost:3000",
  credentials: true
}));
app.use(express.json());
app.use('/uploads', express.static('uploads'));

// Создаём папку для аватарок
if (!fs.existsSync('uploads')) {
  fs.mkdirSync('uploads');
}

// Настройка multer
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, 'uploads/');
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = Date.now() + '-' + Math.round(Math.random() * 1E9);
    cb(null, uniqueSuffix + path.extname(file.originalname));
  }
});

const upload = multer({ 
  storage: storage,
  limits: { fileSize: 5 * 1024 * 1024 },
  fileFilter: (req, file, cb) => {
    if (file.mimetype.startsWith('image/')) {
      cb(null, true);
    } else {
      cb(new Error('Только изображения!'));
    }
  }
});

// ========== БАЗА ДАННЫХ ==========
const db = new Database('chatty.db');

// Создаём таблицы
db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    email TEXT UNIQUE NOT NULL,
    password TEXT NOT NULL,
    displayName TEXT NOT NULL,
    username TEXT UNIQUE NOT NULL,
    phone TEXT,
    avatar TEXT DEFAULT '',
    bio TEXT DEFAULT '',
    theme TEXT DEFAULT 'dark',
    notifications INTEGER DEFAULT 1,
    soundEnabled INTEGER DEFAULT 1,
    online INTEGER DEFAULT 0,
    lastSeen DATETIME DEFAULT CURRENT_TIMESTAMP,
    createdAt DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS conversations (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
    updatedAt DATETIME DEFAULT CURRENT_TIMESTAMP
  );

  CREATE TABLE IF NOT EXISTS conversation_participants (
    conversationId INTEGER,
    userId INTEGER,
    FOREIGN KEY(conversationId) REFERENCES conversations(id) ON DELETE CASCADE,
    FOREIGN KEY(userId) REFERENCES users(id) ON DELETE CASCADE,
    PRIMARY KEY (conversationId, userId)
  );

  CREATE TABLE IF NOT EXISTS messages (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    conversationId INTEGER NOT NULL,
    senderId INTEGER NOT NULL,
    text TEXT NOT NULL,
    read INTEGER DEFAULT 0,
    createdAt DATETIME DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(conversationId) REFERENCES conversations(id) ON DELETE CASCADE,
    FOREIGN KEY(senderId) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE INDEX idx_messages_conversation ON messages(conversationId);
  CREATE INDEX idx_messages_created ON messages(createdAt);
  CREATE INDEX idx_conversations_participants ON conversation_participants(userId);
`);

console.log('✅ База данных готова');

// ========== API РОУТЫ ==========

// РЕГИСТРАЦИЯ
app.post('/api/register', (req, res) => {
  try {
    const { email, password, displayName, username, phone } = req.body;
    
    const existing = db.prepare('SELECT * FROM users WHERE email = ? OR username = ?').get(email, username);
    if (existing) {
      return res.status(400).json({ error: 'Email или username уже используются' });
    }
    
    const hashedPassword = bcrypt.hashSync(password, 10);
    
    const stmt = db.prepare(`
      INSERT INTO users (email, password, displayName, username, phone, theme)
      VALUES (?, ?, ?, ?, ?, 'dark')
    `);
    
    const result = stmt.run(email, hashedPassword, displayName, username, phone || null);
    
    const user = db.prepare('SELECT id, email, displayName, username, phone, avatar, bio, theme, notifications, soundEnabled FROM users WHERE id = ?').get(result.lastInsertRowid);
    
    const token = jwt.sign({ id: user.id }, 'secret123');
    
    res.json({ user, token });
  } catch (error) {
    console.error(error);
    res.status(400).json({ error: error.message });
  }
});

// ВХОД
app.post('/api/login', (req, res) => {
  try {
    const { login, password } = req.body;
    
    const user = db.prepare('SELECT * FROM users WHERE email = ? OR username = ?').get(login, login);
    
    if (!user) {
      return res.status(400).json({ error: 'Пользователь не найден' });
    }
    
    const valid = bcrypt.compareSync(password, user.password);
    if (!valid) {
      return res.status(400).json({ error: 'Неверный пароль' });
    }
    
    const token = jwt.sign({ id: user.id }, 'secret123');
    
    res.json({
      user: {
        id: user.id,
        email: user.email,
        displayName: user.displayName,
        username: user.username,
        phone: user.phone,
        avatar: user.avatar,
        bio: user.bio,
        theme: user.theme,
        notifications: user.notifications,
        soundEnabled: user.soundEnabled
      },
      token
    });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

// ЗАГРУЗКА АВАТАРКИ
app.post('/api/upload-avatar', upload.single('avatar'), (req, res) => {
  try {
    const token = req.headers.authorization?.split(' ')[1];
    const decoded = jwt.verify(token, 'secret123');
    
    if (!req.file) {
      return res.status(400).json({ error: 'Файл не загружен' });
    }
    
    const avatarUrl = `/uploads/${req.file.filename}`;
    
