      SELECT 
        c.id,
        c.updatedAt,
        (
          SELECT json_group_array(
            json_object(
              'id', u.id,
              'displayName', u.displayName,
              'username', u.username,
              'avatar', u.avatar,
              'online', u.online
            )
          )
          FROM conversation_participants cp
